    "source_span": null
  },
  "outcome": {
    "value": "miscarriage",
    "confidence": "explicit",
    "source_span": "miscarriage"
  },
  "is_food_claim": true,
  "scope_rejection_reason": null,
  "notes": null
}

Example 2
